    "keyPoints": [
      "3-5 fundamental bullet points"
    ],
    "detailedContent": "In-depth content discussion with examples"
  },
  "activities": [
    {
      "name": "Name of classroom task",
      "instructions": [
        "Step-by-step instructions for teachers & students"
      ],
      "durationMinutes": 10
    }
  ],
  "materials": {
    "ppt": {
      "title": "Presentation title",
      "slides": [
        {
          "slideTitle": "Slide title",
          "bulletPoints": [
            "Key point"
          ]
        }
      ]
    },
    "pdf": {
      "documentTitle": "Document title",
      "keyInformation": [
        "Key info"
      ]
    },
    "docx": {
      "outlineTitle": "Outline title",
      "sections": [
        "Section content"
      ]
    }
  },
  "homework": {
    "task": "Interactive or practical homework task",
    "estimatedTimeMinutes": 30
  },
  "assessment": {
